	private static void clearActiveSingleTriples(SketchBasedJoinEstimator estimator) throws Exception {
		for (Object array : stateComponentValues(activeState(estimator), "singleTriples")) {
			clearSketchArray((AtomicReferenceArray<?>) array);
		}
	}

	private static void clearActiveSingles(SketchBasedJoinEstimator estimator) throws Exception {
		for (Object singleBuild : stateComponentValues(activeState(estimator), "singles")) {
			@SuppressWarnings("unchecked")
			Map<?, AtomicReferenceArray<?>> complements = (Map<?, AtomicReferenceArray<?>>) field(singleBuild, "cmpl");
			for (AtomicReferenceArray<?> sketches : complements.values()) {
				clearSketchArray(sketches);
			}
		}
	}

	private static void clearActivePairs(SketchBasedJoinEstimator estimator) throws Exception {
		@SuppressWarnings("unchecked")
		Map<?, ?> pairs = (Map<?, ?>) field(activeState(estimator), "pairs");
		for (Object pairBuild : pairs.values()) {
			invokeNoArg(pairBuild, "clear");
		}
	}

